#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvStart = vUv;

vec4 trigWork = sin( vUv.yxyx * uAspect.yxyx * vec2( 6.0, 26.0 ).xxyy + uTime * 1.9 );
vec4 uvWork = vUv.xyxy + (trigWork.xyxy - trigWork.zwzw) * vec2( 0.003, 0.04 ).xxyy;
vUv = uvWork.xy;


vec3 last = GetPixel( vUv );// - vec3( 1.0/255.0, 1.0/255.0, 0.0 );
last.b -= 1.0/255.0;
vec4 dots = texture3D( sampler_noisevol_lq, vec3( uvWork.zw * uAspect * 3.0, + uTime*0.05 ) );// fract( (vUv.xyyx) * vec4( 3.0, 3.0, 4.0, 4.0 ) );
dots = dots*dots*1.1;//fract( dots.x ) > 0.8;
last.b = max( last.b, dots.x );
last.rg = 0.0;

ret = last;

//zw of botcoords is can coords
//note: uAspect.y is 1.0/uAspectY from per uFrame - widescreen is < 1.0
vec2 uvS = vec2( uvStart.x, uvStart.y - VertShift) * uAspect.xy;
uvS.y = uvS.y;


vec2 graffCoords = uvS * 1.8 * vec2( 1.0, 4.0 * 256.0/275.0 ) + vec2( -0.6, -1.2 );
graffCoords.xy = (graffCoords.xy-vec2(0.25,0.5))*GraffScale+vec2(0.25,0.5);
graffCoords.xy += dot( last.rrb, vec3(2.0,2.0,1.0) ) * q23 * 0.15;

vec2 graffMask2 = abs( graffCoords - 0.5 ) < 0.5;
float graffMask = min( graffMask2.x, graffMask2.y );
vec4 graff = 0.5;
vec2 graffSwipe = smoothstep( Swipe.xy, Swipe.zw, graffCoords.xx );// smoothstep( 1.0-Swipe*1.3, 1.0-(Swipe*1.3-0.3), graffCoords.xx ) ;
if( graffMask > 0.5 )
{
   graffCoords.y = graffCoords.y * 0.25 + floor(q20) * 0.25;
   graff = textureLod( sampler_graffBotGraff00, vec4(graffCoords,0.0, (1.0-graffSwipe.y)*5.0 + q23*5.0 ) );
}
graff.a *= graffMask;
graff = mix( vec4( 0.5,0.5,0.5,0.0 ), graff, graffSwipe.x * (1.0-q23) );






//zw of botcoords is can coords
vec4 botCoords = uvS.xyxy * vec4( 0.6, 0.6, CanStart.xy ) - vec4( 0.35, 0.08, CanStart.zw );
vec2 botCoordsStart = botCoords; botCoords.xy +=  - vec4( AnimMove, 0.0, 0.0 );
botCoords.zw = mix( botCoords.zw, (botCoordsStart-vec2(0.18,0.25))*CanStart.xy+vec2(0.27,0.25), CanAnimTime );

botCoords.zw = mix( botCoords.zw, botCoordsStart, CanGrowTime );
botCoords.zw = multiply( botCoords.zw-1.0/8.0, CanRotMat ) + 1.0/8.0;

botCoords.xy += dot( last, vec3(2.0,2.0,1.0)) * BotExitTime * 0.05;
vec4 botMask2 = abs( botCoords * 4.0 - 0.5 ) < 0.5;
vec2 botMask = botMask2.xz * botMask2.yw;

vec4 bot = 0;
vec4 can = 0;
if( botMask.x > 0.5 )
{
  bot = textureBias( sampler_graffBotAnim01, vec4( botCoords.xy + AnimOffset, 0.0, -2.0 ) );
  bot = dot( bot, AnimChannel );
  bot -= BotExitTime*BotExitTime;
}
if( botMask.y > 0.5 )
{
  can = texture( sampler_graffBotAnim01, botCoords.zw );
}
bot = smoothstep( vec4( 0.015, 0.45, 0.7, 0.95 ), vec4( 0.27, 0.55, 0.8, 1.0 ), bot.r );

bot = vec4( dot( bot.gba, 1.0/3.0 ).xxx, bot.x );
bot.a *= 1.0 - BotExitTime;

can = smoothstep( vec4( 0.015, 0.45, 0.7, 0.95 ), vec4( 0.3, 0.55, 0.8, 1.0 ), can.r );
can = vec4( dot( can.gba, 1.0/3.0 ).xxx, can.x );


vec2 uvZoom = (uvStart-0.5)*0.985 + 0.5;
float shadowLast = GetPixel(uvZoom).g * 1.01;//- 10.0/256.0;

ret.g = max(bot.a,can.a);//mix( bot.a*0.5, shadowLast, clamp01( shadowLast * 2.0 ) );
ret.g = max( ret.g, sqrt(graff.a)*0.97 );

//ret = bot.a;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvb = (vUv-0.5)*0.9+0.5;
float tilt = 0.5*sin(uTime*.03);
uvb = (vUv-0.5)*0.9+0.5;
uv2 = 1.9*(vUv-0.5) / (2+(vUv.y-0.5)*tilt);

chan = floor(num/2+uv2.x*num);
sig  = GetBlur1(vec2(0.99,chan/num)).r/uAspect.y;
sig2 = GetBlur1(vec2(0.99,chan/num)).g/uAspect.y;
sig3 = GetBlur2(vec2(0.99,chan/num)).r*1/uAspect.y;
sig4 = GetBlur3(vec2(0.99,uv2.x+0.5)).r*2/uAspect.y;

targ = 6.28*(uv2.x*num)-0.5;
tube0 = sat(0.25-0.75*cos(targ));
tube  = tube0* sat (200*sig-abs(500*(-uv2.y +0.002*tube0*sign(uv2.y))));
tube  = tube*0.25+exp(-4*abs(tube-0.3))*(tube>0);

//dots = pow(tube0,2)* exp(abs(200*sig2-abs(500*(-uv2.y+tube0*.01*sign(uv2.y)))));
dots = pow(tube0,2)* 2/abs(200*sig2-abs(500*(-uv2.y+tube0*.004*sign(uv2.y))));

//dots = pow(tube0,2)* (abs(200*sig2-abs(500*(-uv2.y+tube0*.004*sign(uv2.y))))<3);
dotmask = dots>.2;
uvb += -.05*sin(uTime+targ ) * ((tube>0)||dotmask) ;
col0 = scol(vUv.x+uTime/12);
col =  col0* sat(sig3*16-0.5);
col2 = (col0+0.5)* sat(sig4*16-0.5);

float cld = texture(sampler_noise_hq,vUv/8+uTime*0.002).r;
back = 0.2*cld*vec3 (0,0.6,1);
back *= GP(uvb).b;
back += GP(uvb).r/2;
back += GP(uvb).r*(0.5+col)*(sig4*3*vUv.y);
back *= 1.25;
//back *= sat (1-2*GP(uvb).g); //dark stars

back += exp(-12*length(uvb.y-0.5+(GP(uvb).b-0.5)*.6*rand_preset*vRadius))*col2*0.5*sqrt(audioMidSmooth);

ret = back + (dots + tube/2)*col;
ret += !tube * exp(-3/sig/tube0*abs(uv2.y))*(col+0.5)*sig;

ret += .1*dotmask*(1-dots/4);//*GetBlur1(uvb).r*41;

//ret = GetPixel(vUv);

  fragColor = ret;
}
